import React from 'react';
import { Box, Container, Grid } from '@mui/material';
import SectionTitle from './SectionTitle';
import ServiceCard from './ServiceCard';
import { 
  Web as WebIcon, 
  PhoneAndroid as MobileIcon, 
  SmartToy as BotIcon,
  Security as SecurityIcon 
} from '@mui/icons-material';
import { motion } from 'framer-motion';

const ServicesSection = () => {
  const services = [
    {
      icon: <WebIcon fontSize="large" />,
      title: "Web Application Development",
      description: "End-to-end web application solutions with robust backend systems and intuitive user interfaces.",
      features: [
        "Secure authentication systems",
        "RESTful API development",
        "Database design & optimization",
        "Responsive UI/UX implementation"
      ],
      color: "#2196f3" // Blue
    },
    {
      icon: <MobileIcon fontSize="large" />,
      title: "Mobile Application Development",
      description: "Performant mobile applications with seamless backend integration and cross-platform compatibility.",
      features: [
        "Native & cross-platform solutions",
        "API integration",
        "Real-time data synchronization",
        "Offline-first functionality"
      ],
      color: "#00bcd4" // Teal
    },
    {
      icon: <BotIcon fontSize="large" />,
      title: "AI ChatBot Development",
      description: "Intelligent conversational agents powered by modern AI technologies and natural language processing.",
      features: [
        "Intent recognition systems",
        "Natural language processing",
        "Integration with third-party services",
        "Continuous training & improvement"
      ],
      color: "#7c4dff" // Purple
    },
    {
      icon: <SecurityIcon fontSize="large" />,
      title: "Security Consulting",
      description: "Comprehensive security audits and solutions to protect your systems and sensitive data.",
      features: [
        "Vulnerability assessment",
        "Authentication systems",
        "Data encryption strategies",
        "Security best practices"
      ],
      color: "#ff5722" // Orange
    }
  ];

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box
      sx={{
        py: { xs: 8, md: 12 },
        bgcolor: 'background.darker',
        position: 'relative'
      }}
    >
      {/* Background dots */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundImage: 'radial-gradient(circle, rgba(33, 150, 243, 0.05) 1px, transparent 1px)',
          backgroundSize: '30px 30px',
          zIndex: 0,
        }}
      />
      
      <Container maxWidth="lg" sx={{ position: 'relative', zIndex: 1 }}>
        <SectionTitle 
          title="Services" 
          subtitle="What I Can Do For You" 
        />
        
        <Grid 
          container 
          spacing={4}
          component={motion.div}
          variants={containerVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
        >
          {services.map((service, index) => (
            <Grid item xs={12} sm={6} md={6} key={index}>
              <ServiceCard {...service} />
            </Grid>
          ))}
        </Grid>
      </Container>
    </Box>
  );
};

export default ServicesSection;
